foreach {tn a b} {
  1   'helloworld'  '12345'
  2   22            23
} {
  set as [db one "SELECT $a"]
  set bs [db one "SELECT $b"]

  do_execsql_test e_expr-5.$tn "SELECT $a || $b" [list "${as}${bs}"]
}

